{
  "name": "Founder OS HQ",
  "version": "1.0.0",
  "description": "Complete Notion workspace template for Founder OS. Consolidates 32+ plugin databases into 21 interconnected databases with CRM Companies as the central hub.",
  "sections": [
    {
      "name": "CRM",
      "icon": "building",
      "description": "The CRM core. Companies is the central hub; all client-facing databases relate back here.",
      "databases": [
        "hq-companies",
        "hq-contacts",
        "hq-deals",
        "crm-sync-hub-communications"
      ]
    },
    {
      "name": "Operations",
      "icon": "clipboard",
      "description": "Day-to-day operational records: tasks, meetings, and financial documents.",
      "databases": [
        "hq-tasks",
        "hq-meetings",
        "hq-finance"
      ]
    },
    {
      "name": "Intelligence",
      "icon": "brain",
      "description": "Briefings, knowledge base, research, and reports generated by intelligence plugins.",
      "databases": [
        "hq-briefings",
        "hq-knowledge-base",
        "hq-research",
        "hq-reports"
      ]
    },
    {
      "name": "Content & Deliverables",
      "icon": "pencil",
      "description": "Content creation (newsletters, posts, drafts) and client deliverables (proposals, contracts, SOWs).",
      "databases": [
        "hq-content",
        "hq-deliverables",
        "team-prompt-library-prompts"
      ]
    },
    {
      "name": "Growth & Meta",
      "icon": "chart_increasing",
      "description": "Goal tracking, learning logs, workflow automation, and activity logging.",
      "databases": [
        "goal-progress-tracker-goals",
        "goal-progress-tracker-milestones",
        "learning-log-tracker-learnings",
        "learning-log-tracker-weekly-insights",
        "hq-workflows",
        "google-drive-brain-activity",
        "hq-memory",
        "hq-intelligence"
      ]
    }
  ],
  "creation_order": [
    "hq-companies",
    "hq-contacts",
    "hq-deals",
    "crm-sync-hub-communications",
    "hq-tasks",
    "hq-meetings",
    "hq-finance",
    "hq-briefings",
    "hq-knowledge-base",
    "hq-research",
    "hq-reports",
    "hq-content",
    "hq-deliverables",
    "team-prompt-library-prompts",
    "goal-progress-tracker-goals",
    "goal-progress-tracker-milestones",
    "learning-log-tracker-learnings",
    "learning-log-tracker-weekly-insights",
    "hq-workflows",
    "google-drive-brain-activity",
    "hq-memory",
    "hq-intelligence"
  ],
  "creation_order_notes": "Order matters: relation targets must exist before sources. Companies/Contacts/Deals first (CRM core), then databases that relate to them. Goals before Milestones. Learnings before Weekly Insights.",
  "relations": [
    { "from": "hq-contacts", "property": "Company", "to": "hq-companies" },
    { "from": "hq-deals", "property": "Company", "to": "hq-companies" },
    { "from": "hq-deals", "property": "Deliverables", "to": "hq-deliverables" },
    { "from": "crm-sync-hub-communications", "property": "Contact", "to": "hq-contacts" },
    { "from": "crm-sync-hub-communications", "property": "Company", "to": "hq-companies" },
    { "from": "hq-tasks", "property": "Company", "to": "hq-companies" },
    { "from": "hq-tasks", "property": "Contact", "to": "hq-contacts" },
    { "from": "hq-meetings", "property": "Company", "to": "hq-companies" },
    { "from": "hq-finance", "property": "Company", "to": "hq-companies" },
    { "from": "hq-research", "property": "Company", "to": "hq-companies" },
    { "from": "hq-content", "property": "Company", "to": "hq-companies" },
    { "from": "hq-deliverables", "property": "Company", "to": "hq-companies" },
    { "from": "hq-deliverables", "property": "Deal", "to": "hq-deals" },
    { "from": "goal-progress-tracker-milestones", "property": "Goal", "to": "goal-progress-tracker-goals" },
    { "from": "hq-memory", "property": "Company", "to": "hq-companies" }
  ],
  "dashboard": {
    "title": "Command Center",
    "description": "Main landing page with linked database views for at-a-glance workspace visibility.",
    "widgets": [
      {
        "title": "Today's Priorities",
        "source_db": "hq-tasks",
        "view_type": "table",
        "filter": {
          "and": [
            { "or": [
              { "property": "Deadline", "date": { "equals": "today" } },
              { "property": "Deadline", "date": { "before": "today" } }
            ]},
            { "property": "Status", "select": { "does_not_equal": "Done" } }
          ]
        },
        "sort": [{ "property": "Priority", "direction": "ascending" }],
        "visible_columns": ["Title", "Type", "Priority", "Deadline", "Owner", "Status"]
      },
      {
        "title": "Client Health",
        "source_db": "hq-companies",
        "view_type": "table",
        "filter": {
          "or": [
            { "property": "Health Status", "select": { "equals": "Yellow" } },
            { "property": "Health Status", "select": { "equals": "Red" } }
          ]
        },
        "sort": [{ "property": "Health Score", "direction": "ascending" }],
        "visible_columns": ["Name", "Health Score", "Health Status", "Risk Flags", "Last Scanned"]
      },
      {
        "title": "Upcoming Meetings",
        "source_db": "hq-meetings",
        "view_type": "table",
        "filter": {
          "property": "Date",
          "date": { "next_week": {} }
        },
        "filter_notes": "Ideally 'next 48 hours' but Notion API supports 'next_week' as closest filter. Refine in Notion UI.",
        "sort": [{ "property": "Date", "direction": "ascending" }],
        "visible_columns": ["Meeting Title", "Date", "Meeting Type", "Attendees", "Company"]
      },
      {
        "title": "Recent Activity",
        "source_db": "crm-sync-hub-communications",
        "view_type": "table",
        "filter": {
          "property": "Date",
          "date": { "past_week": {} }
        },
        "sort": [{ "property": "Date", "direction": "descending" }],
        "visible_columns": ["Title", "Type", "Date", "Company", "Sentiment"]
      },
      {
        "title": "Pipeline",
        "source_db": "hq-deals",
        "view_type": "board",
        "board_group_by": "Stage",
        "filter": {
          "and": [
            { "property": "Stage", "select": { "does_not_equal": "Closed Won" } },
            { "property": "Stage", "select": { "does_not_equal": "Closed Lost" } }
          ]
        },
        "visible_columns": ["Name", "Value", "Company", "Probability", "Close Date"]
      },
      {
        "title": "Open Follow-Ups",
        "source_db": "hq-tasks",
        "view_type": "table",
        "filter": {
          "and": [
            { "property": "Type", "select": { "equals": "Follow-Up" } },
            { "property": "Status", "select": { "equals": "Waiting" } }
          ]
        },
        "sort": [{ "property": "Days Waiting", "direction": "descending" }],
        "visible_columns": ["Title", "Days Waiting", "Priority", "Nudge Count", "Company"]
      },
      {
        "title": "Active Goals",
        "source_db": "goal-progress-tracker-goals",
        "view_type": "table",
        "filter": {
          "property": "Status",
          "select": { "equals": "In Progress" }
        },
        "sort": [{ "property": "Target Date", "direction": "ascending" }],
        "visible_columns": ["Title", "Progress", "RAG Status", "Target Date", "Category"]
      },
      {
        "title": "Latest Briefing",
        "source_db": "hq-briefings",
        "view_type": "table",
        "filter_notes": "Show most recent briefing by Generated At. In Notion UI, set limit to 1 row.",
        "sort": [{ "property": "Generated At", "direction": "descending" }],
        "limit": 1,
        "visible_columns": ["Title", "Type", "Date", "Content"]
      }
    ]
  },
  "workspace_pages": [
    {
      "title": "Founder OS HQ",
      "icon": "rocket",
      "children": [
        { "title": "Command Center", "type": "dashboard" },
        { "title": "CRM", "icon": "building", "type": "section" },
        { "title": "Operations", "icon": "clipboard", "type": "section" },
        { "title": "Intelligence", "icon": "brain", "type": "section" },
        { "title": "Content & Deliverables", "icon": "pencil", "type": "section" },
        { "title": "Growth & Meta", "icon": "chart_increasing", "type": "section" }
      ]
    }
  ]
}

{
  "title": "Founder OS HQ - Tasks",
  "description": "Consolidated task database merging P01 Inbox Zero action items, P04 Action Item Extractor tasks, and P06 Follow-Up Tracker follow-ups. Each record has a Type column indicating its source.",
  "plugin": "founder-os-hq",
  "properties": {
    "Title": {
      "type": "title",
      "description": "Task description"
    },
    "Description": {
      "type": "rich_text",
      "description": "Detailed task description"
    },
    "Type": {
      "type": "select",
      "description": "Task origin type",
      "options": ["Action Item", "Follow-Up", "Email Task"]
    },
    "Source Plugin": {
      "type": "select",
      "description": "Plugin that created this record",
      "options": ["Inbox Zero", "Action Extractor", "Follow-Up Tracker"]
    },
    "Owner": {
      "type": "rich_text",
      "description": "Person responsible for the task"
    },
    "Status": {
      "type": "select",
      "description": "Current status",
      "options": ["To Do", "In Progress", "Done", "Waiting"]
    },
    "Priority": {
      "type": "number",
      "description": "Priority level 1-5 (1=highest)"
    },
    "Deadline": {
      "type": "date",
      "description": "Due date"
    },
    "Company": {
      "type": "relation",
      "description": "Optional: associated company",
      "relation_database": "Founder OS HQ - Companies"
    },
    "Contact": {
      "type": "relation",
      "description": "Optional: associated contact",
      "relation_database": "Founder OS HQ - Contacts"
    },
    "Source Type": {
      "type": "select",
      "description": "Where the task was extracted from",
      "options": ["Email", "Meeting", "Document", "Manual"]
    },
    "Source Title": {
      "type": "rich_text",
      "description": "Title/subject of the source document/email"
    },
    "Promise Type": {
      "type": "select",
      "description": "P06: Direction of commitment",
      "options": ["Outbound", "Inbound"]
    },
    "Days Waiting": {
      "type": "number",
      "description": "P06: Days since follow-up was created"
    },
    "Nudge Count": {
      "type": "number",
      "description": "P06: Number of nudges sent"
    },
    "Thread ID": {
      "type": "rich_text",
      "description": "Gmail Thread ID for deduplication of email-sourced tasks"
    },
    "Extracted At": {
      "type": "date",
      "description": "When the task was extracted/created"
    }
  },
  "default_values": {
    "Status": "To Do",
    "Priority": 3
  },
  "notes": "Merged database for all task-like records. Plugins filter by Type when reading (e.g., P06 queries Type='Follow-Up'). Deduplication: P01 and P04 use Title + Source Title within their Type; P06 uses Thread ID. Company/Contact relations are populated when email domain or attendee info maps to a CRM record. Discovery: search 'Founder OS HQ - Tasks' first, then fall back to plugin-specific DB names ('Inbox Zero - Action Items', 'Action Item Extractor - Tasks', 'Follow-Up Tracker - Follow-Ups')."
}

{
  "title": "Founder OS HQ - Deliverables",
  "description": "Consolidated deliverables database merging P12 Proposal Automator proposals, P13 Contract Analyzer contract analyses, and P14 SOW Generator statements of work.",
  "plugin": "founder-os-hq",
  "properties": {
    "Title": {
      "type": "title",
      "description": "Project title, contract name, or SOW title"
    },
    "Type": {
      "type": "select",
      "description": "Deliverable type",
      "options": ["Proposal", "Contract", "SOW"]
    },
    "Company": {
      "type": "relation",
      "description": "Associated client/company",
      "relation_database": "Founder OS HQ - Companies"
    },
    "Deal": {
      "type": "relation",
      "description": "Optional: associated sales deal",
      "relation_database": "Founder OS HQ - Deals"
    },
    "Status": {
      "type": "select",
      "description": "Deliverable lifecycle",
      "options": ["Draft", "Sent", "Under Review", "Signed", "Rejected", "Expired"]
    },
    "Amount": {
      "type": "number",
      "description": "Total monetary value (proposals/SOWs)"
    },
    "Package Selected": {
      "type": "select",
      "description": "P12: Pricing tier selected",
      "options": ["Good", "Better", "Best"]
    },
    "Risk Level": {
      "type": "select",
      "description": "P13: Contract risk assessment",
      "options": ["Green", "Yellow", "Red"]
    },
    "Risk Flags": {
      "type": "rich_text",
      "description": "P13: Detailed risk flag descriptions (JSON)"
    },
    "Contract Type": {
      "type": "select",
      "description": "P13: Type of contract",
      "options": ["SaaS", "Freelance", "Agency", "NDA", "Employment", "Vendor"]
    },
    "Key Terms": {
      "type": "rich_text",
      "description": "P13: Extracted key contract terms"
    },
    "File Path": {
      "type": "rich_text",
      "description": "Path to generated document"
    },
    "Brief File": {
      "type": "rich_text",
      "description": "P12/P14: Path to the brief file used"
    },
    "Sources Used": {
      "type": "multi_select",
      "description": "Data sources consulted",
      "options": ["CRM", "Notion", "Drive", "Email", "Manual"]
    },
    "Generated At": {
      "type": "date",
      "description": "When deliverable was generated"
    }
  },
  "default_values": {
    "Status": "Draft",
    "Type": "Proposal"
  },
  "notes": "P12 Proposal Automator writes Type='Proposal' with Company relation from client name lookup and optional Deal relation. P13 Contract Analyzer writes Type='Contract' with Company relation when contract parties match CRM. P14 SOW Generator writes Type='SOW' with Company + Deal relations. The Deals DB has a reverse relation to Deliverables. Idempotent: by Title + Company (case-insensitive). Discovery: search 'Founder OS HQ - Deliverables' first, then fall back to plugin-specific names."
}

